    private fun ASTNode.isOpeningParenthesisOfFunctionTypeWrappedInNullableType(): Boolean {
        if (elementType != LPAR) {
            return false
        }
        val valueParameterList = treeParent.takeIf { it.elementType == VALUE_PARAMETER_LIST } ?: return false
        val functionType = valueParameterList.treeParent?.takeIf { it.elementType == FUNCTION_TYPE } ?: return false
        val nullableType = functionType.treeParent?.takeIf { it.elementType == NULLABLE_TYPE } ?: return false
        val previousNonWhitespaceLeaf = prevLeaf { it.elementType != WHITE_SPACE } ?: return false
        return previousNonWhitespaceLeaf.elementType == LPAR && previousNonWhitespaceLeaf.treeParent == nullableType
